        // Local network CIDR ranges
        private val LOCAL_NETWORK_PATTERNS = listOf(
            Regex("""^192\.168\.\d{1,3}\.\d{1,3}$"""),
            Regex("""^10\.\d{1,3}\.\d{1,3}\.\d{1,3}$"""),
