            override fun onResponse(call: Call, response: Response) {
                response.use {
                    val result = HttpResult(
                        statusCode = it.code,
                        body = it.body?.string(),
                        headers = it.headers.toMap()
                    )
                    if (it.isSuccessful) {
                        callback.onSuccess(result)
                    } else {
                        callback.onFailure(
                            HttpException(result.statusCode, result.body ?: "Unknown error")
                        )
                    }
                }
            }
        })
    }

