    private fun buildJsonObject(map: Map<String, Any>): String {
        val entries = map.entries.joinToString(",") { (key, value) ->
            "\"$key\":${valueToJson(value)}"
        }
        return "{$entries}"
    }

    @Suppress("UNCHECKED_CAST")
    private fun valueToJson(value: Any): String {
        return when (value) {
            is String -> "\"$value\""
            is Number -> value.toString()
            is Boolean -> value.toString()
            is Map<*, *> -> buildJsonObject(value as Map<String, Any>)
            is List<*> -> "[${value.joinToString(",") { valueToJson(it ?: "null") }}]"
            else -> "\"$value\""
        }
    }

    private fun Headers.toMap(): Map<String, String> {
        val map = mutableMapOf<String, String>()
        for (i in 0 until size) {
            map[name(i)] = value(i)
        }
        return map
