// ==================== Data Classes & Interfaces ====================

data class HttpResult(
    val statusCode: Int,
    val body: String?,
    val headers: Map<String, String> = emptyMap()
) {
    val isSuccessful: Boolean get() = statusCode in 200..299
}

interface HttpCallback {
    fun onSuccess(result: HttpResult)
    fun onFailure(exception: Exception)
}

class HttpException(val statusCode: Int, message: String) : Exception("HTTP $statusCode: $message")

class CleartextNotPermittedException(message: String) : SecurityException(message)

// ==================== Logging Interceptor ====================

class LoggingInterceptor(private val tag: String) : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val startTime = System.nanoTime()

        android.util.Log.d(tag, "--> ${request.method} ${request.url}")

        return try {
            val response = chain.proceed(request)
            val duration = (System.nanoTime() - startTime) / 1_000_000

            android.util.Log.d(
                tag,
                "<-- ${response.code} ${request.url} (${duration}ms)"
            )

            response
        } catch (e: Exception) {
            android.util.Log.e(tag, "<-- FAILED ${request.url}: ${e.message}")
            throw e
        }
    }
}

